import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"자주 묻는 질문","description":"플레이어와 서버 관리자를 위한 질문과 답변.","frontmatter":{"title":"자주 묻는 질문","description":"플레이어와 서버 관리자를 위한 질문과 답변.","files":[]},"headers":[],"relativePath":"ko_kr/players/faq.md","filePath":"translated/ko_kr/players/faq.md","lastUpdated":1772272927000}`);var a={name:`ko_kr/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">자주 묻는 질문 <a class="header-anchor" href="#h1" aria-label="Permalink to “자주 묻는 질문”">​</a></h1><p>자주 언급되는 질문이 여럿 있으므로, 아래에 간단히 정리했습니다.</p><h2 id="what-minecraft-versions-does-fabric-support" tabindex="-1">Fabric이 지원하는 Minecraft 버전은 무엇인가요? <a class="header-anchor" href="#what-minecraft-versions-does-fabric-support" aria-label="Permalink to “Fabric이 지원하는 Minecraft 버전은 무엇인가요?”">​</a></h2><p>공식적으로, Fabric은 릴리스 <code>1.14</code> 이상, 스냅숏 <code>18w43b</code> 이상의 모든 Minecraft: Java Edition을 지원합니다.</p><h2 id="where-can-i-download-published-fabric-mods" tabindex="-1">어디서 Fabric 모드를 다운로드 할 수 있나요? <a class="header-anchor" href="#where-can-i-download-published-fabric-mods" aria-label="Permalink to “어디서 Fabric 모드를 다운로드 할 수 있나요?”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>마인크래프트 모드는 항상 검증된 출처에서 다운로드해야 합니다. <a href="./finding-mods">안전한 모드 찾기</a>에서 자세한 정보를 확인해보세요.</p></div><p>대부분의 모드 개발자는 <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> 또는 <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a> 에 모드를 업로드 하지만, 몇몇 사람들은 개인 웹사이트나 GitHub 레포지토리 등 같은 다른 플랫폼에 모드를 업로드하는 경우도 있습니다.</p><h2 id="where-can-i-find-pre-made-fabric-modpacks" tabindex="-1">Fabric 모드팩은 어디에서 찾을 수 있나요? <a class="header-anchor" href="#where-can-i-find-pre-made-fabric-modpacks" aria-label="Permalink to “Fabric 모드팩은 어디에서 찾을 수 있나요?”">​</a></h2><p>먼저 생성된 Fabric 모드팩은 다음과 같이 여러 플랫폼에서 찾을 수 있습니다:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};